{{ if eq .Title .Site.Title }}{{ .Site.Title }}{{ else }}{{ with .Title }}{{ . }} sur {{ end }}{{ .Site.Title }}{{ end }}
{{ .Permalink }}
Flux RSS des Avis de Vacances de Poste - {{ .Site.Title }}
Hugo -- gohugo.io
{{ site.Language.Locale | default .Site.LanguageCode }}


  {{ "assets/logo-opt.png" | absURL }}
  {{ .Site.Title }}
  {{ .Permalink }}


{{ with .OutputFormats.Get "RSS" }}
    {{ printf "" .Permalink .MediaType.Type | safeHTML }}
{{ end }}

{{ range .Site.RegularPages }}
  {{/* 🎯 FILTRES D'EXCLUSION : On identifie les pages à ignorer */}}
  {{ $isMotDrh := eq .Section "mot-drh" }}
  {{ $isAPropos := in .Permalink "a-propos" }}
  {{ $is404 := in .Permalink "404" }}
  {{ $isSearch := in .Permalink "search" }}

  {{/* Si la page n'est AUCUNE de ces trois-là, on génère l'item RSS */}}
  {{ if and (not $isMotDrh) (not $isAPropos) (not $is404) (not $isSearch) }}


    {{ .Title }}
    {{ .Permalink }}
    {{ .Date.Format "Mon, 02 Jan 2006 15:04:05 -0700" | safeHTML }}
    {{ .Permalink }}
    {{ or .Description .Summary | html }}

    {{/* 🎯 INJECTION DE L'ILLUSTRATION NANO BANANA DE L'AVP */}}
    {{ with .Params.featured_image }}
      {{/* 1. Balise standard RSS 2.0 */}}


      {{/* 2. Balise enrichie Yahoo/Media RSS pour les agrégateurs modernes */}}

    {{ end }}

  {{ end }}
{{ end }}
